import{_ as d,o as e,c as r,ag as n}from"./chunks/framework.ePeAWSvT.js";const p=JSON.parse('{"title":"Drill Intents & Entity Model","description":"","frontmatter":{},"headers":[],"relativePath":"guide/drill-intents.md","filePath":"guide/drill-intents.md"}'),a={name:"guide/drill-intents.md"};function o(i,t,l,c,s,h){return e(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="drill-intents-entity-model" tabindex="-1">Drill Intents &amp; Entity Model <a class="header-anchor" href="#drill-intents-entity-model" aria-label="Permalink to &quot;Drill Intents &amp; Entity Model&quot;">​</a></h1><h2 id="what-is-an-entity" tabindex="-1">What Is an Entity? <a class="header-anchor" href="#what-is-an-entity" aria-label="Permalink to &quot;What Is an Entity?&quot;">​</a></h2><p>Every visible data point in the terminal is an <strong>EntityRef</strong> — a typed, drillable object.</p><h3 id="entitykind-types" tabindex="-1">EntityKind Types <a class="header-anchor" href="#entitykind-types" aria-label="Permalink to &quot;EntityKind Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Kind</th><th>Examples</th><th>Opens in</th></tr></thead><tbody><tr><td><code>SECURITY</code></td><td>AAPL US Equity</td><td>DES, HP, GP, FA</td></tr><tr><td><code>INDEX</code></td><td>SPX Index</td><td>DES, WEI, GP</td></tr><tr><td><code>FX</code></td><td>EURUSD Curncy</td><td>DES, GP, FXC</td></tr><tr><td><code>RATE</code></td><td>US10YT</td><td>GC, LINE</td></tr><tr><td><code>FUTURE</code></td><td>CL1 Comdty</td><td>DES, GP</td></tr><tr><td><code>OPTION</code></td><td>AAPL option</td><td>CHAIN, SURF</td></tr><tr><td><code>ETF</code></td><td>QQQ US Equity</td><td>DES, ETFM</td></tr><tr><td><code>COMPANY</code></td><td>Apple Inc</td><td>CMPY, RELG</td></tr><tr><td><code>SECTOR</code></td><td>Technology</td><td>SECT, IMAP</td></tr><tr><td><code>INDUSTRY</code></td><td>Semiconductors</td><td>INDY, SCN</td></tr><tr><td><code>COUNTRY</code></td><td>US, JP, DE</td><td>CTY, GEO</td></tr><tr><td><code>PERSON</code></td><td>CEO name</td><td>MGMT</td></tr><tr><td><code>HOLDER</code></td><td>Institutional holder</td><td>OWN</td></tr><tr><td><code>NEWS</code></td><td>Headline</td><td>NTIM, NREL</td></tr><tr><td><code>EVENT</code></td><td>Earnings, dividend</td><td>EVT</td></tr><tr><td><code>FIELD</code></td><td>PX_LAST, PE_RATIO</td><td>LINE, FLD</td></tr><tr><td><code>FUNCTION</code></td><td>DES, WEI, GP</td><td>Navigates to that function</td></tr><tr><td><code>MONITOR</code></td><td>Custom watchlist</td><td>MON</td></tr><tr><td><code>WORKSPACE</code></td><td>Saved workspace</td><td>WS</td></tr><tr><td><code>ALERT</code></td><td>Alert rule</td><td>ALRT</td></tr><tr><td><code>ORDER</code></td><td>Submitted order</td><td>BLTR</td></tr><tr><td><code>TRADE</code></td><td>Executed trade</td><td>BLTR</td></tr></tbody></table><h2 id="drill-intents" tabindex="-1">Drill Intents <a class="header-anchor" href="#drill-intents" aria-label="Permalink to &quot;Drill Intents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Intent</th><th>Trigger</th><th>Behavior</th></tr></thead><tbody><tr><td><code>OPEN_IN_PLACE</code></td><td>Click</td><td>Open entity in current pane, replacing current view</td></tr><tr><td><code>OPEN_IN_NEW_PANE</code></td><td>Shift+Click or Shift+Enter</td><td>Open entity in next available pane or create new one</td></tr><tr><td><code>INSPECT_OVERLAY</code></td><td>Alt+Click or Alt+Enter</td><td>Open Inspector overlay without navigating away</td></tr><tr><td>Context menu</td><td>Right-click</td><td>Show all available actions for entity</td></tr></tbody></table><h2 id="the-inspector-overlay" tabindex="-1">The Inspector Overlay <a class="header-anchor" href="#the-inspector-overlay" aria-label="Permalink to &quot;The Inspector Overlay&quot;">​</a></h2><p>Opening the Inspector (Alt+Click) shows:</p><ul><li><strong>Header</strong>: entity display name, kind, provenance (SIM/LIVE/STALE), last updated</li><li><strong>Key fields</strong>: dense key-value grid (each field is itself a FIELD entity, clickable → LINE)</li><li><strong>Related entities</strong>: list of associated entities (clickable → drill further)</li><li><strong>Related functions</strong>: relevant mnemonics for this entity type</li><li><strong>Evidence</strong>: source confidence chain</li></ul><p><strong>Inspector history</strong>: Use back/forward arrows within Inspector to navigate the inspect chain.<br><strong>Pin</strong>: Keep Inspector open while clicking elsewhere in the panel.</p><h2 id="provenance-badges" tabindex="-1">Provenance Badges <a class="header-anchor" href="#provenance-badges" aria-label="Permalink to &quot;Provenance Badges&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Badge</th><th>Meaning</th></tr></thead><tbody><tr><td><code>SIM</code></td><td>Simulated data — realistic but not live market data</td></tr><tr><td><code>LIVE</code></td><td>Live-streamed value (when live mode enabled)</td></tr><tr><td><code>STALE</code></td><td>Value has exceeded its expected refresh cadence</td></tr><tr><td><code>CALC</code></td><td>Derived/calculated from other fields</td></tr></tbody></table>',13)])])}const y=d(a,[["render",o]]);export{p as __pageData,y as default};
